'use strict';(function(){const indexCfg={};indexCfg.doc={id:'id',field:['title','content'],store:['title','href','parent'],};const index=FlexSearch.create(indexCfg);window.geekdocSearchIndex=index;index.add({'id':0,'href':'/','title':"Home",'parent':'','content':"Welcome to alexsalter.net but the truth is at this point you\u0026rsquo;re probably lost.\n"});index.add({'id':1,'href':'/note/debian/audioengine-hd3/','title':"Audioengine HD3",'parent':"Debian",'content':"The Audioengine HD3 speakers do not appear to support a sample rate of 44.1kHz which is the default.\nWe therefore need change the sample rate to 48kHz and restart pulseaudio.\nsed \\  -i \u0026#39;s/; default-sample-rate = 44100/default-sample-rate = 48000/g\u0026#39; \\  /etc/pulse/daemon.conf pulseaudio -k "});index.add({'id':2,'href':'/note/','title':"Notes",'parent':"Home",'content':""});index.add({'id':3,'href':'/note/debian/setup/','title':"Setup",'parent':"Debian",'content':" Drivers  "});index.add({'id':4,'href':'/note/debian/packages/','title':"Packages",'parent':"Debian",'content':"Frequently used packages\n   Name Description     bridge-utils Utilities for configuring the Linux Ethernet bridge   dnsutils Clients provided with BIND   htop interactive processes viewer   hwinfo Hardware identification system    "});index.add({'id':5,'href':'/note/debian/','title':"Debian",'parent':"Notes",'content':""});index.add({'id':6,'href':'/note/debian/dell-xps-15-9560/','title':"Dell XPS 15 9560",'parent':"Debian",'content':"Installer missing non-free wifi firmware The Intel 8265/8275 requires non-free firmware whoever this can be added to the installation media.\nCopy the non-free firmware-iwlwifi_*_all.deb from https://cdimage.debian.org/cdimage/unofficial/non-free/firmware/ to firmware folder of the installation media.\nACPI issue There is currently a bug that means that some kernels (particularly newer ones) will detect the wrong ACPI revision.\nAdd acpi_rev_override=5 to /etc/default/grub\nGRUB_CMDLINE_LINUX=\u0026#34;acpi_rev_override=5 quiet\u0026#34; Update grub\nupdate-grub Reference    Name Link     Debian XPS 15 9560 https://wiki.debian.org/InstallingDebianOn/Dell/Dell_XPS_15_9560   Non-free firmware https://cdimage.debian.org/cdimage/unofficial/non-free/firmware/    "});index.add({'id':7,'href':'/categories/','title':"Categories",'parent':"Home",'content':""});index.add({'id':8,'href':'/tags/','title':"Tags",'parent':"Home",'content':""});})();